1	import { formatProbability } from "@/lib/utils/format";
2	import type { MarketOutcome } from "@/lib/api/types";
3	
4	const OUTCOME_COLORS = [
5	  "#22c55e", "#ef4444", "#3b82f6", "#eab308", "#a855f7",
6	  "#ec4899", "#14b8a6", "#f97316",
7	];
8	
9	interface ProbabilityBarProps {
10	  outcomes: MarketOutcome[];
11	  marginals: Record<string, number>;
12	}
13	
14	export function ProbabilityBar({ outcomes, marginals }: ProbabilityBarProps) {
15	  return (
16	    <div>
17	      <div
18	        style={{
19	          display: "flex",
20	          height: 24,
21	          borderRadius: "var(--radius-sm)",
22	          overflow: "hidden",
23	          background: "var(--color-bg)",
24	        }}
25	      >
26	        {outcomes.map((o, i) => {
27	          const p = marginals[o.id] ?? 0;
28	          return (
29	            <div
30	              key={o.id}
31	              style={{
32	                width: `${p * 100}%`,
33	                background: OUTCOME_COLORS[i % OUTCOME_COLORS.length],
34	                transition: "width 0.3s ease",
35	                minWidth: p > 0 ? 2 : 0,
36	              }}
37	              title={`${o.name}: ${formatProbability(p)}`}
38	            />
39	          );
40	        })}
41	      </div>
42	      <div style={{ display: "flex", gap: "var(--space-md)", marginTop: "var(--space-xs)", fontSize: "0.8rem" }}>
43	        {outcomes.map((o, i) => (
44	          <span key={o.id} style={{ color: OUTCOME_COLORS[i % OUTCOME_COLORS.length] }}>
45	            {o.name} {formatProbability(marginals[o.id] ?? 0)}
46	          </span>
47	        ))}
48	      </div>
49	    </div>
50	  );
51	}
