1	import type { AnalyticsInterval } from "@/lib/api/types";
2	import { formatCurrency } from "@/lib/utils/format";
3	
4	const OUTCOME_COLORS = [
5	  "#818cf8",
6	  "#22c55e",
7	  "#f59e0b",
8	  "#38bdf8",
9	  "#f97316",
10	  "#f472b6",
11	];
12	
13	export function getOutcomeColor(index: number): string {
14	  return OUTCOME_COLORS[index % OUTCOME_COLORS.length] ?? "#818cf8";
15	}
16	
17	export function scaleNumber(
18	  value: number,
19	  domainMin: number,
20	  domainMax: number,
21	  rangeMin: number,
22	  rangeMax: number,
23	): number {
24	  if (domainMax === domainMin) {
25	    return (rangeMin + rangeMax) / 2;
26	  }
27	
28	  const ratio = (value - domainMin) / (domainMax - domainMin);
29	  return rangeMin + (rangeMax - rangeMin) * ratio;
30	}
31	
32	export function buildLinePath(points: Array<{ x: number; y: number }>): string {
33	  return points
34	    .map((point, index) => `${index === 0 ? "M" : "L"} ${point.x.toFixed(2)} ${point.y.toFixed(2)}`)
35	    .join(" ");
36	}
37	
38	export function formatTimestampLabel(iso: string, interval: AnalyticsInterval): string {
39	  const date = new Date(iso);
40	  if (interval === "hour") {
41	    return `${date.toLocaleDateString([], { month: "short", day: "numeric" })} ${date.toLocaleTimeString([], {
42	      hour: "numeric",
43	      minute: "2-digit",
44	    })}`;
45	  }
46	
47	  return date.toLocaleDateString([], { month: "short", day: "numeric" });
48	}
49	
50	export function formatBucketRangeLabel(
51	  bucketStart: string,
52	  bucketEnd: string,
53	  interval: AnalyticsInterval,
54	): string {
55	  if (interval === "day") {
56	    return formatTimestampLabel(bucketStart, interval);
57	  }
58	
59	  const start = new Date(bucketStart);
60	  const end = new Date(bucketEnd);
61	  return `${start.toLocaleTimeString([], { hour: "numeric", minute: "2-digit" })} - ${end.toLocaleTimeString([], {
62	    hour: "numeric",
63	    minute: "2-digit",
64	  })}`;
65	}
66	
67	export function formatSignedCurrency(value: number): string {
68	  const prefix = value > 0 ? "+" : "";
69	  return `${prefix}${formatCurrency(value)}`;
70	}
